import { Component, OnInit, ViewChild, Input, Inject, PLATFORM_ID } from '@angular/core';

import { MapsAPILoader } from '@agm/core';
import { isPlatformBrowser } from '@angular/common';

@Component({
  selector: 'app-google',
  templateUrl: './google.component.html',
  styleUrls: ['./google.component.scss']
})

/**
 * Google Maps Component
 */
export class GoogleComponent implements OnInit {

  // bread crumb items
  breadCrumbItems!: Array<{}>;
  longitude = 20.728218;
  latitude = 52.128973;
  markers: any;
  zoom: number = 15;
  @ViewChild('streetviewMap', { static: true }) streetviewMap: any;
  @ViewChild('streetviewPano', { static: true }) streetviewPano: any;

  constructor(@Inject(PLATFORM_ID) private platformId: any, private mapsAPILoader: MapsAPILoader) { }

  ngOnInit(): void {
    /**
    * BreadCrumb
    */
    this.breadCrumbItems = [
      { label: 'Maps' },
      { label: 'Google Maps', active: true }
    ];

      /**
    * fetches data
    */
    this._fetchData();

    this._initPanorama();
  }

   /**
   * Fetches the value of map
   */
    private _fetchData() {
      this.markers = [
        { latitude: 52.228973, longitude: 20.728218 }
      ];
    }

    /**
     *
     * @param position position where marker added
     */
     placeMarker(position: any) {
      const lat = position.coords.lat;
      const lng = position.coords.lng;
      this.markers.push({ latitude: lat, longitude: lng });
    }

    /**
     * street view map
     */
     _initPanorama() {
      if (isPlatformBrowser(this.platformId)) {
        // this.mapsAPILoader.load().then(() => {
        //   const center = { lat: 42.345573, lng: -71.098326 };
        //   // tslint:disable-next-line: no-string-literal
        //   const map = new window['google'].maps.Map(this.streetviewMap.nativeElement, { center, zoom: 12, scrollwheel: false });
        //   // tslint:disable-next-line: no-string-literal
        //   const panorama = new window['google'].maps.StreetViewPanorama(
        //     this.streetviewPano.nativeElement, {
        //     position: center,
        //     pov: { heading: 34, pitch: 10 },
        //     scrollwheel: false
        //   });
        //   map.setStreetView(panorama);
        // });
      }
    }

}
<!-- Start Breadcrumbs -->
<app-breadcrumbs title="Google Maps" [breadcrumbItems]="breadCrumbItems"></app-breadcrumbs>
<!-- End Breadcrumbs -->

<div class="row">
  <div class="col-lg-6">
      <div class="card">
          <div class="card-header">
              <h4 class="card-title mb-0">Markers</h4>
          </div><!-- end card header -->

          <div class="card-body">
            <agm-map [latitude]="latitude" [longitude]="longitude" style="height: 300px">
            </agm-map>
          </div><!-- end card-body -->
      </div><!-- end card -->
  </div>
  <!-- end col -->

  <div class="col-lg-6">
      <div class="card">
          <div class="card-header">
              <h4 class="card-title mb-0">Overlays</h4>
          </div><!-- end card header -->

          <div class="card-body">
            <agm-map [latitude]="latitude" [longitude]="longitude" style="height: 300px" (mapClick)="placeMarker($event)">
              <agm-marker *ngFor="let marker of markers" [latitude]="marker.latitude" [longitude]="marker.longitude">
                <agm-info-window [disableAutoPan]="false" #infoWindow>
                  <strong>InfoWindow content</strong>
                </agm-info-window>
              </agm-marker>
            </agm-map>
          </div><!-- end card-body -->
      </div><!-- end card -->
  </div>
  <!-- end col -->
</div>
<!-- end row -->

<div class="row">

  <div class="col-lg-6">
      <div class="card">
          <div class="card-header">
              <h4 class="card-title mb-0">Location</h4>
          </div><!-- end card header -->

          <div class="card-body">
            <agm-map [latitude]="latitude" [longitude]="longitude" style="height: 300px">
              <agm-circle [latitude]="latitude" [longitude]="longitude" [radius]="9000" [fillColor]="'red'"
                [circleDraggable]="true" [editable]="true">
              </agm-circle>
            </agm-map>
          </div><!-- end card-body -->
      </div><!-- end card -->
  </div>
  <!-- end col -->
</div>
<!-- end row -->
